import { Effect, Duration, Data } from "effect";

interface Response { readonly status: number; readonly body: string }

class NetworkError extends Data.TaggedError("NetworkError")<{ readonly url: string }> {}
class TimeoutError extends Data.TaggedError("TimeoutError")<{ readonly ms: number }> {}

declare const httpGet: (url: string) => Effect.Effect<Response, NetworkError>;

const timeout = (ms: number): Effect.Effect<never, TimeoutError> =>
  Effect.sleep(Duration.millis(ms)).pipe(
    Effect.flatMap(() => Effect.fail(new TimeoutError({ ms })))
  );

export const fetchWithTimeout = (
  url: string
): Effect.Effect<Response, NetworkError | TimeoutError> =>
  Effect.race(httpGet(url), timeout(2000));
```

`Effect.race` runs both effects concurrently; whichever finishes first wins and the loser fiber is interrupted automatically. The error channel unions both tagged errors so callers can `catchTag` either branch.

