import { Effect, Fiber } from "effect";

declare const prefetchCatalog: Effect.Effect<ReadonlyArray<string>>;
declare const renderShell: Effect.Effect<void>;

export const boot: Effect.Effect<ReadonlyArray<string>> = Effect.gen(function* () {
  const fiber = yield* Effect.fork(prefetchCatalog);
  yield* renderShell;
  const catalog = yield* Fiber.join(fiber);
  return catalog;
});
```

`Effect.fork` starts `prefetchCatalog` on a new fiber and returns a handle immediately, so `renderShell` runs in parallel. `Fiber.join` then awaits the forked fiber's result — if it hasn't finished, the join suspends; if it already finished, the value is delivered synchronously.

