class CacheMiss extends Data.TaggedError("CacheMiss")<{ readonly key: string }> {}
class DbError extends Data.TaggedError("DbError")<{ readonly reason: string }> {}

interface Row { readonly id: string; readonly value: string }

declare const cacheGet: (key: string) => Effect.Effect<Row, CacheMiss>;
declare const dbGet: (key: string) => Effect.Effect<Row, DbError>;

export const readWithFallback = (key: string): Effect.Effect<Row, DbError> =>
  Effect.race(
    cacheGet(key).pipe(Effect.catchTag("CacheMiss", () => dbGet(key))),
    dbGet(key)
  );
