import { Effect, Data } from "effect";

class ScoreError extends Data.TaggedError("ScoreError")<{ readonly scorer: string }> {}

declare const scoreA: (x: number) => Effect.Effect<number, ScoreError>;
declare const scoreB: (x: number) => Effect.Effect<number, ScoreError>;
declare const scoreC: (x: number) => Effect.Effect<number, ScoreError>;

export const firstScore = (x: number): Effect.Effect<number, ScoreError> =>
  Effect.gen(function* () {
    return yield* Effect.raceAll([scoreA(x), scoreB(x), scoreC(x)]);
  });
```

`Effect.raceAll` takes a non-empty iterable and resolves with the first success, interrupting every other fiber. Unlike `Promise.race`, a fiber's failure does not end the race — Effect keeps waiting for a success, returning the last error only when all racers fail.

```ts
import { Effect, Fiber, Duration, Data } from "effect";

class WatchdogExpired extends Data.TaggedError("WatchdogExpired")<{ readonly ms: number }> {}

declare const heavyCompute: Effect.Effect<number>;

export const guardedCompute = (
  deadlineMs: number
): Effect.Effect<number, WatchdogExpired> =>
  Effect.gen(function* () {
    const fiber = yield* Effect.fork(heavyCompute);
    const winner = yield* Effect.race(
      Fiber.join(fiber),
      Effect.sleep(Duration.millis(deadlineMs)).pipe(
        Effect.flatMap(() => Fiber.interrupt(fiber)),
        Effect.flatMap(() => Effect.fail(new WatchdogExpired({ ms: deadlineMs })))
      )
    );
    return winner;
  });
```

The race is between the joined result and the deadline. If the sleep wins, `Fiber.interrupt` stops the compute fiber before the watchdog error is raised, so no orphaned work is left running.

`Effect.fork(effect)` launches `effect` on a new fiber and returns a `Fiber<A, E>` handle; the parent continues immediately. Calling `Fiber.join(fiber)` later suspends the parent until the fiber completes and re-raises any typed error into the parent's error channel. Fibers are structurally concurrent — if the parent is interrupted, its children are interrupted too.

```ts
import { Effect, Fiber, Data } from "effect";

class FetchError extends Data.TaggedError("FetchError")<{ readonly url: string }> {}

declare const fetchUsers: Effect.Effect<ReadonlyArray<string>, FetchError>;
declare const fetchOrders: Effect.Effect<ReadonlyArray<string>, FetchError>;

export const loadBoth: Effect.Effect<
  readonly [ReadonlyArray<string>, ReadonlyArray<string>],
  FetchError
> = Effect.gen(function* () {
  const f1 = yield* Effect.fork(fetchUsers);
  const f2 = yield* Effect.fork(fetchOrders);
  const users = yield* Fiber.join(f1);
  const orders = yield* Fiber.join(f2);
  return [users, orders] as const;
});
```

Both HTTP calls start immediately; the two joins wait for their respective fibers without forcing sequential execution.

