import { Effect, Fiber, Ref, Duration, Data } from "effect";

class PollError extends Data.TaggedError("PollError")<{ readonly reason: string }> {}

declare const fetchStatus: () => Effect.Effect<"pending" | "done", PollError>;

const pollLoop = (done: Ref.Ref<boolean>): Effect.Effect<void, PollError> =>
  Effect.gen(function* () {
    const s = yield* fetchStatus();
    if (s === "done") {
      yield* Ref.set(done, true);
      return;
    }
    yield* Effect.sleep(Duration.seconds(1));
    yield* pollLoop(done);
  });

export const startPolling = Effect.gen(function* () {
  const done = yield* Ref.make(false);
  const fiber = yield* Effect.fork(pollLoop(done));
  return { fiber, done } as const;
});

export const cancelPolling = (fiber: Fiber.Fiber<void, PollError>) =>
  Fiber.interrupt(fiber);
```

The loop sleeps between polls so the fiber is interruptible at each suspension point. `Fiber.interrupt` stops the loop cleanly — any in-flight sleep is cancelled and the fiber terminates.

