declare const emitMetric: Effect.Effect<void>;
declare const mainWork: Effect.Effect<number>;

const reporter: Effect.Effect<never> = Effect.gen(function* () {
  while (true) {
    yield* emitMetric;
    yield* Effect.sleep(Duration.seconds(10));
