declare const fetchOrders: (userId: string) => Effect.Effect<ReadonlyArray<Order>, FetchError>;

const program = (id: string) => Effect.gen(function* () {
  const u = yield* fetchUser(id);
  const o = yield* fetchOrders(u.id);
  return { u, o } as const;
